  ('heelevel3-6e11b43e-moex-00145', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-112-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '下列公法上財產請求權，何者不因2年間不行使而消滅？', '["經服務機關核准之加班費", "執行職務時，發生意外致受傷應發給之慰問金", "執行職務墊支之必要費用", "經服務機關核准實施公務人員一般健康檢查之費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:23+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00146', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-112-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '關於公務員之懲戒程序，下列敘述何者錯誤？', '["懲戒案件係由懲戒法院設懲戒法庭，合議審理並裁判之", "公務員懲戒案件之審理制度係採一級一審", "應受懲戒行為，自行為終了之日起，至案件繫屬懲戒法院之日止，已逾10年者，不得予以休職 之懲戒", "公務員雖非執行職務，但其個人行為若致嚴重損害政府信譽，亦應受懲戒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:23+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00147', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-112-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '行政機關發布命令，禁止餐廳營業時間超過晚上9點。下列敘述何者錯誤？', '["該命令須送立法院審查", "該命令之訂定須有法律授權", "該命令屬於行政規則", "該命令應刊登政府公報或新聞紙 31550、31650 32250、32950 33050 33850"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:23+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00148', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-112-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '關於受託行使公權力之私人或團體，下列敘述何者錯誤？', '["受委託者於受託範圍內得作出行政處分", "授權之法律有明定受託者得訂定法規命令者，受託之私人或團體不需委託機關特別授權，即得 發布法規命令", "受委託者即使無法律授權，亦得將其受託之權限再委託其他私人或團體", "受委託者於受託範圍內得立於機關之地位作出事實行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:23+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00149', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-112-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '財政部以營利事業欠稅為由，函請內政部移民署限制營利事業負責人出境，並通知營利事業負責 人。下列敘述何者錯誤？', '["限制出境之決定乃係行政處分", "限制出境之決定係內政部移民署所作成的行政處分", "內政部移民署所為限制出境之決定屬多階段行政處分", "營利事業負責人不得以不服財政部通知為由向行政院提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:23+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00150', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-112-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '行政機關發現經其核准受領疫情紓困補助的受益人，有重複領取情形，於其撤銷原處分後，應採 取何種方式追回溢發之款項？', '["作成書面行政處分確認返還範圍，並限期命受益人返還", "向行政法院提起一般給付訴訟", "向民事法院提起請求返還不當得利訴訟", "直接移送法務部行政執行署所屬分署執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:23+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00151', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-112-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '行政處分於法定救濟期間經過後，當事人仍得於一定情形下申請撤銷、廢止或變更之。下列敘述 何者錯誤？', '["具有持續效力之行政處分，其依據之事實事後發生有利變更者，相對人或利害關係人得提出申請", "該項申請應自法定救濟期間經過後3個月內為之", "雖有重新開始程序之原因，行政機關如認為原處分為正當者，仍應駁回該申請", "相對人或利害關係人因過失未能在行政程序中主張其事由者，即不得提出該項申請"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:23+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL)
